// Input: items = [{ output: "{ ...json string...}" }, ...]
// Output: items = [{ json: { linkedin_profile, icp_score, ... } }, ...]

function safeJsonParse(str) {
  if (typeof str !== 'string') return null;

  // Remove possible ```json fences if your agent sometimes adds them
  const cleaned = str
    .replace(/^\s*```json\s*/i, '')
    .replace(/^\s*```\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    return {
      _parse_error: true,
      _error_message: e.message,
      _raw_output: str,
    };
  }
}

return items.map((item) => {
  const parsed = safeJsonParse(item.json?.output ?? item.output);

  // Normalize + provide predictable keys for downstream nodes
  return {
    json: {
      linkedin_profile: parsed?.linkedin_profile ?? null,
      icp_score: parsed?.icp_score ?? null,
      icp_reasoning: parsed?.icp_reasoning ?? null,
      message_1: parsed?.message_1 ?? null,
      message_2: parsed?.message_2 ?? null,
      message_3: parsed?.message_3 ?? null,

      // Keep the full parsed object too (handy for debugging/extra fields)
      _parsed: parsed,
    },
  };
});
